require "config.SeasonConfig"

local GUIToolBar = class("UIToolBar", IGUILayout)

function GUIToolBar:onLoad()
    self.windowPosRecord = {}
    self.curRank = 0
    self.curHonor = 0
    self.ivPlayerDan = self:getChildWindow("LuckySkyHallToolBar-Dan-Icon", GUIType.StaticImage)
    self.tvPlayerDanRank = self:getChildWindow("LuckySkyHallToolBar-Dan-Text", GUIType.StaticText)
    self.tvPlayerHonor = self:getChildWindow("LuckySkyHallToolBar-Integral-Text", GUIType.StaticText)

    self:hideEngineWindow("ToolBar-Currency-Money")
    self:registerDataCallBack("CurrentSeasonInfo", function(data)
        self:initSeasonRank(data)
    end, DataBuilderProcessor)
end

function GUIToolBar:initSeasonRank(data)
    local honorId = data:getNumberParam("honorId")
    local curSeason = SeasonConfig:getSeasonByHonorId(honorId)
    if not curSeason then
        return
    end
    local rank = data:getNumberParam("rank")
    self.curRank = rank
    local honor = data:getNumberParam("honor")
    self.curHonor = honor

    self.ivPlayerDan:SetImage(curSeason.danIcon)
    self.tvPlayerDanRank:SetText(string.format("No.%s",tostring(self.curRank)))
    self.tvPlayerHonor:SetText(tostring(self.curHonor))

end

function GUIToolBar:hideEngineWindow(name)
    local window = GUIManager:getWindowByName(name)
    if not window then
        return
    end
    self.windowPosRecord[name] = window:GetXPosition()
    window:SetXPosition({ 200, 0 })
end

function GUIToolBar:isNeedLoad()
    return not Game:isEnableIndie()
end

return GUIToolBar